// Função para simular a busca de nós
const searchNodes = (query, includeExamples = true) => {
  // Aqui seria implementada a lógica real de busca nos nós do n8n
  // Esta é uma implementação simplificada para demonstração

  const nodes = [
    {
      name: "HTTP Request",
      type: "n8n-nodes-base.httpRequest",
      description: "Faz requisições HTTP para qualquer API",
      version: 1,
      group: ["input", "output"]
    },
    {
      name: "Webhook",
      type: "n8n-nodes-base.webhook",
      description: "Recebe requisições HTTP",
      version: 1,
      group: ["trigger"]
    },
    {
      name: "Function",
      type: "n8n-nodes-base.function",
      description: "Executa código JavaScript personalizado",
      version: 1,
      group: ["transform"]
    },
    {
      name: "Set",
      type: "n8n-nodes-base.set",
      description: "Define valores nos itens de dados",
      version: 1,
      group: ["transform"]
    }
  ];

  // Filtra os nós pela query
  const filtered = query 
    ? nodes.filter(node => 
        node.name.toLowerCase().includes(query.toLowerCase()) || 
        node.description.toLowerCase().includes(query.toLowerCase()) ||
        node.type.toLowerCase().includes(query.toLowerCase()))
    : nodes;

  // Adiciona exemplos se solicitado
  if (includeExamples) {
    return filtered.map(node => ({
      ...node,
      examples: [
        {
          name: "Exemplo básico",
          config: getExampleConfig(node.type)
        }
      ]
    }));
  }

  return filtered;
};

