// Função para validar a configuração de um nó
const validateNode = (nodeType, config, mode = 'minimal', profile = 'runtime') => {
  // Aqui seria implementada a lógica real de validação
  // Esta é uma implementação simplificada para demonstração

  // Define as regras de validação por tipo de nó
  const validationRules = {
    "n8n-nodes-base.httpRequest": {
      required: ['url', 'method', 'authentication'],
      rules: {
        url: {
          type: 'string',
          required: true,
          minLength: 5,
          startsWith: 'http'
        },
        method: {
          type: 'string',
          enum: ['GET', 'POST', 'PUT', 'DELETE', 'HEAD', 'OPTIONS', 'PATCH']
        },
        authentication: {
          type: 'string',
          enum: ['none', 'basicAuth', 'headerAuth', 'oAuth2', 'digestAuth']
        }
      }
    },
    "n8n-nodes-base.webhook": {
      required: ['httpMethod', 'path'],
      rules: {
        httpMethod: {
          type: 'string',
          enum: ['GET', 'POST', 'HEAD', 'OPTIONS']
        },
        path: {
          type: 'string',
          required: true,
          minLength: 1,
          pattern: '^[a-zA-Z0-9-_/]+$'
        },
        'options.responseMode': {
          type: 'string',
          enum: ['onReceived', 'responseNode', 'lastNode']
        }
      }
    }
  };

  // Verifica se o tipo de nó é suportado
  if (!validationRules[nodeType]) {
    return {
      error: true,
      message: `Tipo de nó ${nodeType} não suportado para validação`
    };
  }

  const rules = validationRules[nodeType];
  const errors = [];

  // Modo minimal: verifica apenas campos obrigatórios
  if (mode === 'minimal') {
    // Verifica campos obrigatórios
    for (const field of rules.required) {
      if (!hasNestedProperty(config, field)) {
        errors.push(`Campo obrigatório '${field}' não encontrado`);
      }
    }
  }
  // Modo full: validação completa
  else if (mode === 'full') {
    // Verifica campos obrigatórios
    for (const field of rules.required) {
      if (!hasNestedProperty(config, field)) {
        errors.push(`Campo obrigatório '${field}' não encontrado`);
        continue;
      }

      // Verifica regras específicas para cada campo
      const value = getNestedProperty(config, field);
      const fieldRules = rules.rules[field];

      if (fieldRules) {
        // Verifica tipo
        if (fieldRules.type && typeof value !== fieldRules.type) {
          errors.push(`Campo '${field}' deve ser do tipo ${fieldRules.type}`);
        }

        // Verifica enum
        if (fieldRules.enum && !fieldRules.enum.includes(value)) {
          errors.push(`Campo '${field}' deve ser um dos seguintes valores: ${fieldRules.enum.join(', ')}`);
        }

        // Verifica tamanho mínimo para strings
        if (fieldRules.minLength && typeof value === 'string' && value.length < fieldRules.minLength) {
          errors.push(`Campo '${field}' deve ter pelo menos ${fieldRules.minLength} caracteres`);
        }

        // Verifica prefixo para strings
        if (fieldRules.startsWith && typeof value === 'string' && !value.startsWith(fieldRules.startsWith)) {
          errors.push(`Campo '${field}' deve começar com '${fieldRules.startsWith}'`);
        }

        // Verifica padrão regex
        if (fieldRules.pattern && typeof value === 'string') {
          const regex = new RegExp(fieldRules.pattern);
          if (!regex.test(value)) {
            errors.push(`Campo '${field}' não corresponde ao padrão esperado`);
          }
        }
      }
    }

    // Verificações adicionais baseadas no perfil
    if (profile === 'ai-friendly') {
      // Verifica URL com variáveis dinâmicas não resolvidas
      if (nodeType === 'n8n-nodes-base.httpRequest' && typeof config.url === 'string') {
        if (config.url.includes('{{') && config.url.includes('}}')) {
          errors.push('URL contém expressões que podem não ser resolvidas pelo AI');
        }
      }
    }

    if (profile === 'strict') {
      // Adiciona validações mais rigorosas aqui
    }
  }

  // Retorna o resultado da validação
  const success = errors.length === 0;

  return {
    valid: success,
    errors: errors.length > 0 ? errors : undefined,
    warnings: [],  // Aqui colocaria avisos não críticos
    fixes: success ? undefined : getFixSuggestions(nodeType, config, errors)
  };
};

// Função auxiliar para verificar a existência de propriedades aninhadas
function hasNestedProperty(obj, path) {
  if (!obj || typeof obj !== 'object') return false;

  const parts = path.split('.');
  let current = obj;

  for (const part of parts) {
    if (!current || typeof current !== 'object' || !(part in current)) {
      return false;
    }
    current = current[part];
  }

  return true;
}

// Função auxiliar para obter o valor de propriedades aninhadas
function getNestedProperty(obj, path) {
  if (!obj || typeof obj !== 'object') return undefined;

  const parts = path.split('.');
  let current = obj;

  for (const part of parts) {
    if (!current || typeof current !== 'object' || !(part in current)) {
      return undefined;
    }
    current = current[part];
  }

  return current;
}

// Função para sugerir correções
function getFixSuggestions(nodeType, config, errors) {
  const fixes = {};

  // Exemplos de correções para erros comuns
  if (nodeType === 'n8n-nodes-base.httpRequest') {
    // Corrige URLs sem protocolo
    if (config.url && typeof config.url === 'string' && !config.url.startsWith('http')) {
      fixes.url = `https://${config.url}`;
    }

    // Corrige método HTTP não especificado
    if (!config.method) {
      fixes.method = 'GET';
    }

    // Corrige autenticação não especificada
    if (!config.authentication) {
      fixes.authentication = 'none';
    }
  }

  else if (nodeType === 'n8n-nodes-base.webhook') {
    // Corrige caminho vazio
    if (!config.path || config.path.trim() === '') {
      fixes.path = 'webhook';
    }
  }

  return Object.keys(fixes).length > 0 ? fixes : undefined;
}

// Extrai os parâmetros da requisição
const { nodeType, config, mode = 'minimal', profile = 'runtime' } = $input.item.json.params;

// Valida a configuração do nó
const result = validateNode(nodeType, config, mode, profile);

// Retorna o resultado
return {
  success: true,
  validation: result
};

